// existing docs have no 'plan' field; new ones do.
// nothing breaks, no ALTER TABLE, no downtime.
db.users.updateOne(
  { name: "Ada" },
  { $set: { plan: "pro", trialEndsAt: new Date() } }
)

// create an index on email, then check the plan
db.users.createIndex({ email: 1 })

db.users.find({ email: "ada@example.com" })
  .explain("executionStats")
// look for stage: IXSCAN (good) not COLLSCAN (bad)

// one document, then several at once
db.orders.insertOne({ user: "ada", total: 42, status: "paid" })

db.orders.insertMany([
  { user: "grace", total: 9,  status: "paid" },
  { user: "alan",  total: 80, status: "pending" }
])

// all paid orders over 10, newest first, only 2 fields
db.orders.find(
  { status: "paid", total: { $gt: 10 } },   // filter
  { user: 1, total: 1, _id: 0 }              // projection
).sort({ total: -1 })

// match any of several values
db.orders.find({ status: { $in: ["paid", "refunded"] } })

// set fields with $set, increment a number with $inc
db.orders.updateOne(
  { user: "alan" },
  { $set: { status: "paid" }, $inc: { total: 5 } }
)

// update many at once + create if missing (upsert)
db.orders.updateMany(
  { status: "paid" },
  { $set: { reviewed: true } }
)

// delete one matching document
db.orders.deleteOne({ user: "grace" })

// DANGER: an empty filter matches EVERYTHING
// db.orders.deleteMany({})  <- wipes the collection
db.orders.deleteMany({ status: "pending" })  // scoped, safe

// revenue per user: filter -> group -> sort
db.orders.aggregate([
  { $match: { status: "paid" } },
  { $group: { _id: "$user", revenue: { $sum: "$total" } } },
  { $sort: { revenue: -1 } }
])

// index the field you query, then upsert safely
db.orders.createIndex({ user: 1 })

// create-or-update: no duplicate if 'ada' exists
db.orders.updateOne(
  { user: "ada" },
  { $setOnInsert: { createdAt: new Date() }, $inc: { visits: 1 } },
  { upsert: true }
)

// if explain shows COLLSCAN, you're scanning everything
db.orders.find({ status: "paid" }).explain("executionStats")

// fix: add the index it needed
db.orders.createIndex({ status: 1 })

// reject documents that don't match the rules
db.createCollection("users", {
  validator: { $jsonSchema: {
    bsonType: "object",
    required: ["email"],
    properties: {
      email: { bsonType: "string" },
      age:   { bsonType: "int", minimum: 0 }
    }
  }}
})
